As an AI text model, I cannot directly render or display a 3D image. However, I can provide you with the **complete code** to render a 3D house using **Three.js**, a popular JavaScript library for 3D graphics in the browser.

You can copy the code below, save it as an `.html` file (e.g., `house.html`), and open it in any modern web browser to see the result.

### 3D House Code (HTML + Three.js)

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Render</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: Arial, sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click and drag to rotate • Scroll to zoom</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x800000 }); // Dark Red
        const glassMaterial = new THREE.MeshStandardMaterial({ color: 0xADD8E6, transparent: true, opacity: 0.6 });
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x228B22 });

        // 5. Building the House
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.BoxGeometry(10, 1, 10);
        const floor = new THREE.Mesh(floorGeo, grassMaterial);
        floor.position.y = -0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Walls
        const wallGeo = new THREE.BoxGeometry(10, 6, 8);
        const walls = new THREE.Mesh(wallGeo, wallMaterial);
        walls.position.y = 3;
        walls.castShadow = true;
        walls.receiveShadow = true;
        houseGroup.add(walls);

        // Roof
        const roofGeo = new THREE.ConeGeometry(9, 4, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 8;
        roof.rotation.y = Math.PI / 4;
        roof.castShadow = true;
        houseGroup.add(roof);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 4, 0.5);
        const door = new THREE.Mesh(doorGeo, new THREE.MeshStandardMaterial({ color: 0x333333 }));
        door.position.set(0, 2, 4.26);
        door.castShadow = true;
        houseGroup.add(door);

        // Windows
        const windowGeo = new THREE.BoxGeometry(2, 2, 0.2);
        const win1 = new THREE.Mesh(windowGeo, glassMaterial);
        win1.position.set(-3, 5, 4.1);
        houseGroup.add(win1);

        const win2 = new THREE.Mesh(windowGeo, glassMaterial);
        win2.position.set(3, 5, 4.1);
        houseGroup.add(win2);

        // Tree (Simple Cylinder + Cone)
        const treeGroup = new THREE.Group();
        const trunkGeo = new THREE.CylinderGeometry(0.5, 0.8, 3);
        const trunk = new THREE.Mesh(trunkGeo, new THREE.MeshStandardMaterial({ color: 0x8B4513 }));
        trunk.position.y = 1.5;
        trunk.castShadow = true;
        treeGroup.add(trunk);

        const leavesGeo = new THREE.ConeGeometry(2.5, 5, 8);
        const leaves = new THREE.Mesh(leavesGeo, new THREE.MeshStandardMaterial({ color: 0x006400 }));
        leaves.position.y = 5;
        leaves.castShadow = true;
        treeGroup.add(leaves);

        treeGroup.position.set(-8, 0, 0);
        scene.add(treeGroup);

        // Add House to Scene
        scene.add(houseGroup);

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  **Copy** the code block above.
2.  Create a new file on your computer named `house.html`.
3.  **Paste** the code into that file and save it.
4.  **Double-click** `house.html` to open it in Chrome, Firefox, Safari, or Edge.

### What this code does:
*   **Scene Setup:** Creates a 3D environment with a sky-blue background and fog.
*   **Lighting:** Adds ambient light (soft fill) and a directional light (sun) that casts shadows.
*   **Geometry:** Constructs a house using basic shapes:
    *   A `BoxGeometry` for the walls and floor.
    *   A `ConeGeometry` for the roof.
    *   Smaller boxes for the door and windows.
*   **Interactivity:** Includes `OrbitControls`, allowing you to click and drag to rotate around the house and scroll to zoom in/out.
